```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  auto result = sqlgen::sqlite::connect(db_path)
    .and_then([&records](auto&& conn) {
      return sqlgen::insert_into(conn, records);
    });

  if (!result) {
    throw std::runtime_error("Failed to insert records into table: " + table_name);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {

  auto result = sqlgen::sqlite::connect(db_path)
    .and_then([&](auto&& conn) {
      // Handle different table types
      if (table_name == "Student") {
        return sqlgen::update(conn, "Student"_table)
          .set(col_name + " = ?"_sql, new_value)
          .where("SNo = ?"_sql, std::to_string(record_id))
          .execute();
      }
      else if (table_name == "Course") {
        return sqlgen::update(conn, "Course"_table)
          .set(col_name + " = ?"_sql, new_value)
          .where("CID = ?"_sql, record_id)
          .execute();
      }
      else if (table_name == "Score") {
        return sqlgen::update(conn, "Score"_table)
          .set(col_name + " = ?"_sql, new_value)
          .where("ScID = ?"_sql, record_id)
          .execute();
      }
      else if (table_name == "Major") {
        return sqlgen::update(conn, "Major"_table)
          .set(col_name + " = ?"_sql, new_value)
          .where("MID = ?"_sql, record_id)
          .execute();
      }
      else {
        return sqlgen::Result<void>(std::unexpected(std::make_error_code(std::errc::invalid_argument)));
      }
    });

  if (!result) {
    throw std::runtime_error("Failed to modify record in table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {

  auto result = sqlgen::sqlite::connect(db_path)
    .and_then([&](auto&& conn) {
      // Handle different table types and their primary key formats
      if (table_name == "Student") {
        return sqlgen::exec(conn, 
          "DELETE FROM Student WHERE SNo = ?", record_id);
      }
      else if (table_name == "Course") {
        int id = std::stoi(record_id);
        return sqlgen::exec(conn, 
          "DELETE FROM Course WHERE CID = ?", id);
      }
      else if (table_name == "Score") {
        int id = std::stoi(record_id);
        return sqlgen::exec(conn, 
          "DELETE FROM Score WHERE ScID = ?", id);
      }
      else if (table_name == "Major") {
        int id = std::stoi(record_id);
        return sqlgen::exec(conn, 
          "DELETE FROM Major WHERE MID = ?", id);
      }
      else {
        return sqlgen::Result<void>(std::unexpected(std::make_error_code(std::errc::invalid_argument)));
      }
    });

  if (!result) {
    throw std::runtime_error("Failed to delete record from table: " + table_name);
  }
}
```

Key implementation details:

1. **`add_eas_records`**: Uses `sqlgen::insert_into` with the provided records vector. The template parameter `T` ensures type safety with the database schema.

2. **`modify_eas_records_by_id`**: 
   - Handles different table types with their respective primary key formats
   - Uses `sqlgen::update` with parameterized queries for safety
   - Converts the column name and new value appropriately

3. **`delete_eas_records_by_id`**:
   - Handles different primary key types (string for Student, integer for others)
   - Uses `sqlgen::exec` with parameterized queries
   - Converts string record_id to appropriate types based on table

All functions include proper error handling and throw exceptions with descriptive messages when operations fail. The implementation follows the sqlgen library patterns and maintains type safety with the database schema defined in `eas_common.hpp`.

