Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    rfl::Field<"SNo", std::string> sno;
    rfl::Field<"SName", std::string> sname;
    rfl::Field<"Sex", std::optional<int>> sex = 1;
    rfl::Field<"Birthday", std::optional<std::string>> birthday;
    rfl::Field<"Major", std::optional<int>> major;
    rfl::Field<"Scorses", std::optional<float>> scorses = 0.0f;
    rfl::Field<"Remark", std::optional<std::string>> remark;
  };

  struct Course {
    rfl::Field<"CID", int> cid;
    rfl::Field<"CName", std::string> cname;
    rfl::Field<"Term", std::optional<int>> term = 1;
    rfl::Field<"CTime", std::optional<int>> ctime;
    rfl::Field<"Credit", float> credit = 0.0f;
  };

  struct Score {
    rfl::Field<"SNo", std::string> sno;
    rfl::Field<"CID", int> cid;
    rfl::Field<"Score", std::optional<float>> score;
  };

  void design_eas_database() {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Create Student table
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Student (
        SNo VARCHAR(10) NOT NULL PRIMARY KEY,
        SName VARCHAR(30) NOT NULL,
        Sex INT NULL DEFAULT 1,
        Birthday DATETIME NULL,
        Major INT NULL,
        Scorses FLOAT NULL DEFAULT 0,
        Remark TEXT NULL
      )
    )");

    // Create Course table
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Course (
        CID INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
        CName VARCHAR(30) NOT NULL,
        Term INT NULL DEFAULT 1,
        CTime INT NULL,
        Credit FLOAT NOT NULL DEFAULT 0
      )
    )");

    // Create Score table with composite primary key and foreign keys
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Score (
        SNo VARCHAR(10) NOT NULL,
        CID INT NOT NULL,
        Score FLOAT NULL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      )
    )");
  }

}
```

**Key implementation details:**

1. **Struct Definitions:**
   - Used `rfl::Field` with field names matching the database schema
   - Used `std::optional` for nullable fields
   - Set default values using assignment syntax (`= 1`, `= 0.0f`, etc.)

2. **Database Operations:**
   - Connected to SQLite database using `sqlgen::sqlite::connect()`
   - Used raw SQL `CREATE TABLE` statements with `db.execute()`
   - Implemented all constraints: PRIMARY KEY, FOREIGN KEY, NOT NULL, DEFAULT values
   - Used `AUTOINCREMENT` for Course.CID as SQLite's equivalent to auto_increment
   - Added `IF NOT EXISTS` for idempotent table creation

3. **SQLite-specific Notes:**
   - SQLite uses `AUTOINCREMENT` instead of `auto_increment`
   - `DATETIME` type is stored as TEXT in SQLite but maintains semantic meaning
