  using ORM = sqlgen::ObjectRelationalMapping<
    sqlgen::Member<"title", &CourseStatsView::title>,
    sqlgen::Member<"student_count", &CourseStatsView::student_count>,
    sqlgen::Member<"avg_grade", &CourseStatsView::avg_grade>
  >;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to the SQLite database
  sqlgen::database<sqlgen::sqlite> db("test_db.sqlite");

  // Create Course and Enrollment tables
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Query the database to calculate enrollment statistics
  auto results = db.query<CourseStatsView>(
    "SELECT c.title, COUNT(e.enrollment_id) as student_count, AVG(e.grade) as avg_grade "
    "FROM Course c "
    "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
    "GROUP BY c.course_id, c.title"
  );

  // Convert the results to CourseStats objects
  std::vector<CourseStats> course_stats;
  for (const auto& result : results) {
    course_stats.push_back(CourseStats{
      result.title,
      result.student_count,
      result.avg_grade
    });
  }

  return course_stats;
}

}  // namespace query_course_enrollment_stats

