Here's the complete implementation of the `soft_delete_records` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <algorithm>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true; // Nothing to delete
    }

    try {
        // Connect to the SQLite database
        sqlgen::SQLiteDB db("test_db.sqlite");

        // Start a transaction for better performance and atomicity
        auto transaction = db.transaction();

        // Create a query to update the documents
        auto query = db.update<Document>()
            .set(&Document::is_deleted, 1)
            .set(&Document::deleted_at, sqlgen::DateTime::now());

        // Add WHERE condition for the specified IDs
        query.where(sqlgen::in(&Document::doc_id, ids));

        // Execute the update
        auto result = query.execute();

        // Commit the transaction
        transaction.commit();

        return result.rows_affected() > 0;

    } catch (const std::exception& e) {
        // Handle database errors
        return false;
    }
}

}  // namespace soft_delete_records
```

