void update_eas_table() {
  design_eas_database_with_major();

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // 1. Add a new column `Grade` to the table `Score`, with type `char(1)`, not allowing null values
  sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'A';").value();

  // 2. Modify the column type of `Age` in the table `Student` to `int`, allowing null values
  // Note: Since the Student struct doesn't have an Age column, we need to add it first if it doesn't exist
  // and then modify its type. If it already exists, we just modify the type.

  // First check if Age column exists
  bool age_column_exists = false;
  auto stmt = sqlgen::prepare(conn, "PRAGMA table_info(Student);").value();
  while (sqlgen::step(stmt).value() == sqlgen::sqlite::StepResult::Row) {
    auto name = sqlgen::column<sqlgen::Varchar<>>(stmt, 1).value();
    if (name == "Age") {
      age_column_exists = true;
      break;
    }
  }

  if (age_column_exists) {
    // Age column exists, modify its type
    sqlgen::exec(conn, "ALTER TABLE Student MODIFY COLUMN Age INT;").value();
  } else {
    // Age column doesn't exist, add it with the correct type
    sqlgen::exec(conn, "ALTER TABLE Student ADD COLUMN Age INT;").value();
  }

  // 3. Drop the table `Major`
  sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;").value();
}

} // namespace update_eas_table

