std::vector<DepProj> right_join_departments_projects() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Since SQLite doesn't natively support RIGHT JOIN, we need to simulate it
  // We'll use a UNION approach to properly handle the RIGHT JOIN semantics

  // First part: Get all matching records (equivalent to INNER JOIN)
  auto matchingRows = db.read(
    sqlgen::select(
      sqlgen::columns(&Department::name, &Project::name),
      sqlgen::inner_join<Project, Department>(
        sqlgen::on(&Project::department_id, &Department::department_id)
      )
