  );

  // Second part: Get departments without projects
  auto departmentsWithoutProjects = db.read(
    sqlgen::select(
      sqlgen::columns(&Department::name, sqlgen::value("No Project")),
      sqlgen::where(
        sqlgen::not_exists(
          sqlgen::select(
            sqlgen::columns(&Project::project_id),
            sqlgen::where(sqlgen::eq(&Project::department_id, &Department::department_id))
          )
