namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform RIGHT JOIN between Department and Project tables
  // Note: Since SQLite doesn't natively support RIGHT JOIN, we simulate it using LEFT JOIN
  // by swapping the tables and using left_join with the condition reversed
  auto rows = db.read(
    sqlgen::select(
      sqlgen::columns(&Department::name, &Project::name),
      sqlgen::left_join<Project, Department>(
        sqlgen::on(&Project::department_id, &Department::department_id)
      )
    )
  );

  std::vector<DepProj> results;

  // Iterate through the results and populate the DepProj structs
  for (auto&& row : rows) {
    DepProj depProj;

    // Department name (from the right table - always present in RIGHT JOIN)
    // Since we're simulating RIGHT JOIN with LEFT JOIN by swapping tables,
    // Department is now the right table and will always have a value
    depProj.department_name = row.get<0>();

    // Project name (from the left table - may be null if no matching project)
    // Use value_or to handle potential null values
    depProj.project_name = row.get<1>().value_or("No Project");

    results.push_back(std::move(depProj));
  }

  return results;
}

}  // namespace right_join_departments_projects

