#include <sqlgen/sqlite.hpp>
#include <vector>
#include <iostream>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::database<sqlgen::sqlite> db("test_db.sqlite");

    // Upsert each item using insert-or-replace
    for (const auto& item : items) {
      db.replace(item);
    }

    // Verify the upsert behavior by reading back all items
    auto read_items = db.get_all<Inventory>();

    // Check if all items were successfully upserted
    for (const auto& original_item : items) {
      bool found = false;
      for (const auto& read_item : read_items) {
        if (read_item.item_id == original_item.item_id) {
          // Verify the data matches
          if (read_item.name == original_item.name && 
              read_item.quantity == original_item.quantity) {
            found = true;
            break;
          }
        }
      }

      if (!found) {
        std::cerr << "Verification failed for item_id: " << original_item.item_id << std::endl;
        return false;
      }
    }

    std::cout << "Successfully upserted " << items.size() << " items. Total items in database: " 
              << read_items.size() << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
```

