#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  // Create SQLite database connection
  sqlgen::SQLite db("test_db.sqlite");

  // Drop existing tables if they exist
  db.execute(R"(
    DROP TABLE IF EXISTS Friendship;
    DROP TABLE IF EXISTS User;
  )");

  // Create User table
  db.execute(R"(
    CREATE TABLE User (
      user_id INTEGER PRIMARY KEY,
      username VARCHAR(50) NOT NULL UNIQUE,
      email VARCHAR(100) NOT NULL UNIQUE,
      join_date DATETIME NOT NULL,
      city VARCHAR(50)
    );
  )");

  // Create Friendship table
  db.execute(R"(
    CREATE TABLE Friendship (
      user_id1 INTEGER,
      user_id2 INTEGER,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    );
  )");

  // Insert users
  for (const auto& user : users) {
    db.insert(user);
  }

  // Insert friendships
  for (const auto& friendship : friendships) {
    db.insert(friendship);
  }

  std::vector<FriendConnection> results;

  // 1. Use SELF-JOIN to find mutual friends (friends who share the same friend)
  auto mutual_friends = db.select<MutualFriendsResult>(R"(
    SELECT u1.username AS user1_name, u2.username AS user2_name, COUNT(f1.user_id2) AS mutual_friends_count
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id
    HAVING COUNT(f1.user_id2) > 0;
  )");

  // 2. Use nested query to find users with more than average number of friends
  auto popular_users = db.select<UserFriendCount>(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) AS friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) AS friend_count FROM Friendship GROUP BY user_id1) AS friend_counts
    )
    ORDER BY friend_count DESC;
  )");

  // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
  auto friend_of_friend = db.select<FriendConnection>(R"(
    SELECT DISTINCT u1.username AS user1_name, u3.username AS user2_name
    FROM User u1
    JOIN Friendship f1 ON u1.user_id = f1.user_id1
    JOIN User u2 ON f1.user_id2 = u2.user_id
    JOIN Friendship f2 ON u2.user_id = f2.user_id1
    JOIN User u3 ON f2.user_id2 = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
      );
  )");

  // 4. Count friends per user and identify most connected users
  auto friends_per_user = db.select<UserFriendCount>(R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) AS friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC;
  )");

  // 5. Find users in the same city who are not yet friends (recommendation)
  auto friend_recommendations = db.select<FriendRecommendation>(R"(
    SELECT u1.username AS user1_name, u2.username AS user2_name, u1.city AS city
    FROM User u1
    JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
    WHERE u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f 
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
    ORDER BY u1.city, u1.username;
  )");

  // Return friend-of-friend relationships as the main result
  // You can modify this to return different types of relationships
  for (const auto& connection : friend_of_friend) {
    results.push_back(connection);
  }

  // Print some statistics to console (optional)
  std::cout << "Social Network Analysis Results:" << std::endl;
  std::cout << "Mutual friends relationships found: " << mutual_friends.size() << std::endl;
  std::cout << "Users with above-average friends: " << popular_users.size() << std::endl;
  std::cout << "Friend-of-friend relationships: " << friend_of_friend.size() << std::endl;
  std::cout << "Total users analyzed: " << friends_per_user.size() << std::endl;
  std::cout << "Friend recommendations (same city): " << friend_recommendations.size() << std::endl;

  // Find and display the most connected user
  if (!friends_per_user.empty()) {
    const auto& most_connected = friends_per_user[0];
    std::cout << "Most connected user: " << most_connected.username 
              << " with " << most_connected.friend_count << " friends" << std::endl;
  }

  return results;
}

}  // namespace analyze_social_network

