  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  try {
    // Create database connection
    sqlgen::SQLiteDatabase db("test_db.sqlite");

    // Enable foreign keys (required for SQLite)
    db.execute("PRAGMA foreign_keys = ON");

    // Create tables
    db.createTable<Parent>();
    db.createTable<Child>();

    // Insert parent record
    Parent parent{1, "Test Parent"};
    db.insert(parent);

    // Insert child records with the same parent_id
    Child child1{1, 1, "First child"};
    Child child2{2, 1, "Second child"};
    db.insert(child1);
    db.insert(child2);

    // Verify initial state
    auto children_before = db.select<Child>(sqlgen::where(&Child::parent_id) == 1);
    if (children_before.size() != 2) {
        std::cout << "Error: Expected 2 children before deletion, found " 
                  << children_before.size() << std::endl;
        return false;
    }

    // Delete parent (this should cascade to children)
    db.remove<Parent>(sqlgen::where(&Parent::parent_id) == 1);

    // Verify child rows are automatically deleted
    auto children_after = db.select<Child>(sqlgen::where(&Child::parent_id) == 1);

    // Check if parent was deleted
    auto parents_after = db.select<Parent>(sqlgen::where(&Parent::parent_id) == 1);

    bool cascade_worked = children_after.empty() && parents_after.empty();

    if (cascade_worked) {
        std::cout << "Cascade delete successful: " 
                  << children_before.size() << " child records were automatically deleted" 
                  << std::endl;
    } else {
        std::cout << "Cascade delete failed: " 
                  << children_after.size() << " child records remain after parent deletion" 
                  << std::endl;
    }

    return cascade_worked;

  } catch (const std::exception& e) {
    std::cerr << "Error in cascade_delete_demo: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace cascade_delete_demo
