    db.execute("INSERT INTO Account (account_id, balance, status) VALUES (1, 1000.0, 'active')");
    db.execute("INSERT INTO Account (account_id, balance, status) VALUES (2, 2500.0, 'active')");
    db.execute("INSERT INTO Account (account_id, balance, status) VALUES (3, 500.0, 'inactive')");

    // 2. Update balances and statuses using set operations
    auto update_builder = db.update<Account>();

    // Update balance for account_id = 1
    update_builder
        .set(&Account::balance, 1500.0)
