Alternative implementation using a more direct approach with SQLite's UNION to simulate FULL JOIN (since SQLite doesn't natively support FULL JOIN):

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Create database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Since SQLite doesn't support FULL JOIN directly, we use UNION of LEFT and RIGHT joins
  // First part: LEFT JOIN (all suppliers with their products)
  auto left_join = sqlgen::select(
    sqlgen::columns(
      sqlgen::column<Supplier>(&Supplier::name).as("supplier_name"),
      sqlgen::column<Product>(&Product::name).as("product_name")
    )
  ).from(
    sqlgen::left_join<Supplier, Product>(
      sqlgen::on(&Supplier::supplier_id == &Product::supplier_id)
    )
  );

  // Second part: RIGHT JOIN simulated with LEFT JOIN (products without suppliers)
  auto right_join = sqlgen::select(
    sqlgen::columns(
      sqlgen::column<Supplier>(&Supplier::name).as("supplier_name"),
      sqlgen::column<Product>(&Product::name).as("product_name")
    )
  ).from(
    sqlgen::left_join<Product, Supplier>(
      sqlgen::on(&Product::supplier_id == &Supplier::supplier_id)
    )
  ).where(sqlgen::is_null(&Supplier::supplier_id));

  // Combine with UNION
  auto full_join_query = sqlgen::union_(left_join, right_join);

  // Execute the query and map results to SupProd structs
  std::vector<SupProd> results;

  conn.query(full_join_query, [&results](const std::string& supplier_name, 
                                        const std::optional<std::string>& product_name) {
    SupProd item;
    item.supplier_name = supplier_name;
    item.product_name = product_name;
    results.push_back(std::move(item));
  });

  return results;
}

}  // namespace full_join_suppliers_products
```

The second implementation is more robust since it handles SQLite's limitation of not supporting FULL JOIN natively by using UNION to combine LEFT and RIGHT joins. Both implementations will:

1. Connect to the SQLite database "test_db.sqlite"
2. Perform a FULL JOIN equivalent between suppliers and products
3. Include all suppliers (even those without products) and all products (even those without suppliers)
4. Return the results as a vector of SupProd structures containing supplier names and optional product names

