  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  // Create a connection to the SQLite database
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Build the SQL query using sqlgen's query builder
  auto query = sqlgen::query_builder<Stats>()
    .select(
      sqlgen::column<&User::user_id>(),
      sqlgen::column<&User::name>(),
      sqlgen::count<&Post::post_id>().as("post_count"),
      sqlgen::avg(sqlgen::length<&Post::content>()).as("avg_length")
    )
    .from<User>()
    .left_join<Post>(sqlgen::on<&User::user_id, &Post::user_id>())
    .group_by<&User::user_id, &User::name>();

  // Execute the query and return the results
  return conn.execute(query);
}

